```class Solution {
public:
    bool checkRecord(string s) {
        int absences = 0, consecutiveLate = 0;
        for (char c : s) {
            if (c == 'A') absences++;
            if (c == 'L') consecutiveLate++;
            if (consecutiveLate >= 3) return false;
        }
        return absences <= 2;
    }
};
```

